import{_ as e,H as i,f as l,i as t}from"./chunks/framework.Cvt1eIE0.js";const o="/quote/images/setting/display.png",r="/quote/images/setting/validity.png",n="/quote/images/setting/inventory.png",u="/quote/images/setting/google.png",s="/quote/images/setting/notify.png",p="/quote/images/setting/translate.png",d="/quote/images/smart/communication.png",c="/quote/images/smart/customer-reply.png",h="/quote/images/smart/flow.png",m="/quote/images/smart/accept.png",b="/quote/images/smart/log.png",g="/quote/images/smart/auto-approval.png",Q=JSON.parse('{"title":"设置","description":"","frontmatter":{},"headers":[],"relativePath":"quote/settings-permissions.md","filePath":"quote/settings-permissions.md"}'),q={name:"quote/settings-permissions.md"};function f(P,a,x,k,y,_){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h1><p>本页专门说明 <strong>设置</strong> 页面的各项设置用途。<br> 如果您想知道某个开关会影响哪里、应该在什么场景下开启，可以从这里查看。</p><h2 id="_1-设置页面包含哪些分区" tabindex="-1">1. 设置页面包含哪些分区 <a class="header-anchor" href="#_1-设置页面包含哪些分区" aria-label="Permalink to &quot;1. 设置页面包含哪些分区&quot;">​</a></h2><p>当前 <strong>Settings</strong> 页面主要包含这些标签：</p><ul><li><strong>General</strong></li><li><strong>Notifications</strong></li><li><strong>Translate</strong></li><li><strong>Quote Limits</strong></li><li><strong>Quote File</strong></li><li><strong>SmartFlow</strong></li><li><strong>SMTP</strong></li><li><strong>Email integrations</strong></li></ul><p>下面按标签逐项说明。</p><h2 id="_2-general" tabindex="-1">2. General <a class="header-anchor" href="#_2-general" aria-label="Permalink to &quot;2. General&quot;">​</a></h2><h3 id="_2-1-display-settings" tabindex="-1">2.1 Display settings <a class="header-anchor" href="#_2-1-display-settings" aria-label="Permalink to &quot;2.1 Display settings&quot;">​</a></h3><p>这部分控制前台报价入口、价格显示方式和基础交互行为。</p><p><img src="'+o+'" alt="display"></p><h4 id="hide-price" tabindex="-1">Hide price <a class="header-anchor" href="#hide-price" aria-label="Permalink to &quot;Hide price&quot;">​</a></h4><p>作用：</p><ul><li>隐藏前台客户看到的商品价格、行项目价格和报价总价</li></ul><p>适用场景：</p><ul><li>您不希望客户直接看到价格，希望客户先提交询价</li><li>您的报价依赖业务员人工审核后再给出最终价格</li></ul><p>注意：</p><ul><li>开启后，还需要在主题编辑器中启用对应的 App Embed，前台隐藏价格才会完整生效</li></ul><h4 id="login-to-view-price" tabindex="-1">Login to view price <a class="header-anchor" href="#login-to-view-price" aria-label="Permalink to &quot;Login to view price&quot;">​</a></h4><p>作用：</p><ul><li>只有登录客户才可以查看价格</li></ul><p>适用场景：</p><ul><li>只向已注册客户显示价格</li><li>希望先收集客户身份，再让其查看报价相关价格</li></ul><h4 id="hide-add-to-cart-button" tabindex="-1">Hide &#39;Add to Cart&#39; button <a class="header-anchor" href="#hide-add-to-cart-button" aria-label="Permalink to &quot;Hide &#39;Add to Cart&#39; button&quot;">​</a></h4><p>作用：</p><ul><li>在商品页和集合页隐藏原本的加入购物车按钮，引导客户优先走报价流程</li></ul><p>适用场景：</p><ul><li>您的业务主要以询价为主，而不是直接零售下单</li></ul><h4 id="convert-cart-to-quote" tabindex="-1">Convert cart to quote <a class="header-anchor" href="#convert-cart-to-quote" aria-label="Permalink to &quot;Convert cart to quote&quot;">​</a></h4><p>作用：</p><ul><li>在购物车页面或 mini-cart 中显示 “Convert Cart to Quote” 按钮</li><li>让客户可以把购物车内容直接转换成报价请求</li></ul><p>适用场景：</p><ul><li>客户先像普通购物一样加购，再统一转成询价单</li></ul><h4 id="show-add-to-quote-on-product-pages" tabindex="-1">Show &#39;Add to Quote&#39; on product pages <a class="header-anchor" href="#show-add-to-quote-on-product-pages" aria-label="Permalink to &quot;Show &#39;Add to Quote&#39; on product pages&quot;">​</a></h4><p>作用：</p><ul><li>在商品详情页显示 <code>Add to Quote</code> 按钮</li></ul><h4 id="show-quick-quote-on-product-pages" tabindex="-1">Show &#39;Quick Quote&#39; on product pages <a class="header-anchor" href="#show-quick-quote-on-product-pages" aria-label="Permalink to &quot;Show &#39;Quick Quote&#39; on product pages&quot;">​</a></h4><p>作用：</p><ul><li>在商品详情页显示 <code>Quick Quote</code> 按钮</li></ul><p>适用场景：</p><ul><li>希望客户快速提交单个商品的询价</li></ul><h4 id="show-add-to-quote-on-collection-pages" tabindex="-1">Show &#39;Add to Quote&#39; on collection pages <a class="header-anchor" href="#show-add-to-quote-on-collection-pages" aria-label="Permalink to &quot;Show &#39;Add to Quote&#39; on collection pages&quot;">​</a></h4><p>作用：</p><ul><li>在集合页、产品列表、商品卡片中显示报价按钮</li></ul><p>适用场景：</p><ul><li>希望客户在分类页就能直接发起报价</li></ul><h4 id="button-placement" tabindex="-1">Button placement <a class="header-anchor" href="#button-placement" aria-label="Permalink to &quot;Button placement&quot;">​</a></h4><p>作用：</p><ul><li>控制集合页报价按钮显示在商品价格后面，还是显示在 Add to Cart 后面</li></ul><h4 id="quote-item-quantity" tabindex="-1">Quote item quantity <a class="header-anchor" href="#quote-item-quantity" aria-label="Permalink to &quot;Quote item quantity&quot;">​</a></h4><p>作用：</p><ul><li>允许客户在 quote cart 中直接修改商品数量</li></ul><p>适用场景：</p><ul><li>客户在提交报价前，经常需要自己调整数量</li></ul><h4 id="allow-re-quote-clone" tabindex="-1">Allow Re-Quote (Clone) <a class="header-anchor" href="#allow-re-quote-clone" aria-label="Permalink to &quot;Allow Re-Quote (Clone)&quot;">​</a></h4><p>作用：</p><ul><li>允许客户基于旧报价重新发起一张新的报价单</li><li>前台会显示 <code>Re-Quote</code> 按钮</li></ul><p>适用场景：</p><ul><li>客户经常重复采购相似商品</li><li>需要让客户快速复用旧报价内容</li></ul><h4 id="enable-tiered-pricing" tabindex="-1">Enable tiered pricing <a class="header-anchor" href="#enable-tiered-pricing" aria-label="Permalink to &quot;Enable tiered pricing&quot;">​</a></h4><p>作用：</p><ul><li>启用阶梯定价能力</li><li>报价时可根据数量自动匹配不同单价</li></ul><p>适用场景：</p><ul><li>大宗采购价格需要随数量变化</li></ul><h4 id="enable-utm-source-tracking" tabindex="-1">Enable UTM source tracking <a class="header-anchor" href="#enable-utm-source-tracking" aria-label="Permalink to &quot;Enable UTM source tracking&quot;">​</a></h4><p>作用：</p><ul><li>记录客户提交报价时 URL 中的 UTM 参数</li></ul><p>适用场景：</p><ul><li>想知道报价线索来自哪个广告、渠道或活动</li></ul><h3 id="_2-2-quote-validity-period" tabindex="-1">2.2 Quote validity period <a class="header-anchor" href="#_2-2-quote-validity-period" aria-label="Permalink to &quot;2.2 Quote validity period&quot;">​</a></h3><p>这部分控制报价单多久失效。</p><p><img src="'+r+'" alt="validity"></p><h4 id="enable-quote-validity-period" tabindex="-1">Enable quote validity period <a class="header-anchor" href="#enable-quote-validity-period" aria-label="Permalink to &quot;Enable quote validity period&quot;">​</a></h4><p>作用：</p><ul><li>开启报价有效期控制</li></ul><h4 id="validity-days" tabindex="-1">Validity (days) <a class="header-anchor" href="#validity-days" aria-label="Permalink to &quot;Validity (days)&quot;">​</a></h4><p>作用：</p><ul><li>设置报价单在发送或生效后有效多少天</li></ul><p>适用场景：</p><ul><li>价格、库存、优惠仅在一段时间内有效</li></ul><h3 id="_2-3-inventory-settings" tabindex="-1">2.3 Inventory Settings <a class="header-anchor" href="#_2-3-inventory-settings" aria-label="Permalink to &quot;2.3 Inventory Settings&quot;">​</a></h3><h4 id="enable-inventory-reservation" tabindex="-1">Enable inventory reservation <a class="header-anchor" href="#enable-inventory-reservation" aria-label="Permalink to &quot;Enable inventory reservation&quot;">​</a></h4><p>作用：</p><ul><li>当报价发送后，自动在 Shopify 中为该报价预留库存，直到报价过期</li></ul><p><img src="'+n+'" alt="inventory"></p><p>适用场景：</p><ul><li>库存紧张</li><li>希望客户在有效期内优先锁定库存</li></ul><h3 id="_2-4-google-recaptcha" tabindex="-1">2.4 Google reCAPTCHA <a class="header-anchor" href="#_2-4-google-recaptcha" aria-label="Permalink to &quot;2.4 Google reCAPTCHA&quot;">​</a></h3><p>用于保护前台报价表单，减少机器人和垃圾提交。</p><p><img src="'+u+'" alt="google"></p><h4 id="recaptcha-type" tabindex="-1">reCAPTCHA Type <a class="header-anchor" href="#recaptcha-type" aria-label="Permalink to &quot;reCAPTCHA Type&quot;">​</a></h4><p>支持：</p><ul><li><code>v2 Checkbox</code></li><li><code>v3 Invisible</code></li></ul><p>作用区别：</p><ul><li><strong>v2 Checkbox</strong>：客户需要手动勾选“我不是机器人”</li><li><strong>v3 Invisible</strong>：后台根据行为评分判断是否可疑，客户通常无感知</li></ul><h4 id="quote-cart-page" tabindex="-1">Quote Cart Page <a class="header-anchor" href="#quote-cart-page" aria-label="Permalink to &quot;Quote Cart Page&quot;">​</a></h4><p>作用：</p><ul><li>在 Quote Cart 页面启用 reCAPTCHA</li></ul><h4 id="quick-quote-modal" tabindex="-1">Quick Quote Modal <a class="header-anchor" href="#quick-quote-modal" aria-label="Permalink to &quot;Quick Quote Modal&quot;">​</a></h4><p>作用：</p><ul><li>在 Quick Quote 弹窗中启用 reCAPTCHA</li></ul><h4 id="site-key" tabindex="-1">Site Key <a class="header-anchor" href="#site-key" aria-label="Permalink to &quot;Site Key&quot;">​</a></h4><p>作用：</p><ul><li>Google reCAPTCHA 前端识别 key</li></ul><h4 id="secret-key" tabindex="-1">Secret Key <a class="header-anchor" href="#secret-key" aria-label="Permalink to &quot;Secret Key&quot;">​</a></h4><p>作用：</p><ul><li>Google reCAPTCHA 服务端验证 key</li></ul><h2 id="_3-notifications" tabindex="-1">3. Notifications <a class="header-anchor" href="#_3-notifications" aria-label="Permalink to &quot;3. Notifications&quot;">​</a></h2><p>这部分用于控制通知邮件模板和通知事件是否启用。</p><p><img src="'+s+'" alt="notify"></p><h4 id="enable-notification" tabindex="-1">Enable notification <a class="header-anchor" href="#enable-notification" aria-label="Permalink to &quot;Enable notification&quot;">​</a></h4><p>作用：</p><ul><li>控制当前选中的通知事件是否启用</li></ul><h4 id="event" tabindex="-1">Event <a class="header-anchor" href="#event" aria-label="Permalink to &quot;Event&quot;">​</a></h4><p>支持的通知事件包括：</p><ul><li><code>Quote created</code></li><li><code>Quote updated</code></li><li><code>Quote declined</code></li><li><code>Quote expiry reminder</code></li></ul><h4 id="subject" tabindex="-1">Subject <a class="header-anchor" href="#subject" aria-label="Permalink to &quot;Subject&quot;">​</a></h4><p>作用：</p><ul><li>设置该类通知邮件的标题</li></ul><h4 id="body" tabindex="-1">Body <a class="header-anchor" href="#body" aria-label="Permalink to &quot;Body&quot;">​</a></h4><p>作用：</p><ul><li>设置该类通知邮件正文内容</li></ul><h4 id="send-reminder-before-expiry" tabindex="-1">Send reminder before expiry <a class="header-anchor" href="#send-reminder-before-expiry" aria-label="Permalink to &quot;Send reminder before expiry&quot;">​</a></h4><p>作用：</p><ul><li>仅用于 <code>Quote expiry reminder</code></li><li>设置在报价过期前多少天或多少小时发送提醒</li></ul><h2 id="_4-translate" tabindex="-1">4. Translate <a class="header-anchor" href="#_4-translate" aria-label="Permalink to &quot;4. Translate&quot;">​</a></h2><p>这部分用于修改前台客户可见文案。</p><p><img src="'+p+'" alt="Translate"></p><h4 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h4><p>作用：</p><ul><li>选择当前要编辑的语言</li></ul><h4 id="add-language" tabindex="-1">Add language <a class="header-anchor" href="#add-language" aria-label="Permalink to &quot;Add language&quot;">​</a></h4><p>作用：</p><ul><li>新增一个语言代码，用于维护该语言的前台文案</li></ul><h4 id="各字段翻译输入框" tabindex="-1">各字段翻译输入框 <a class="header-anchor" href="#各字段翻译输入框" aria-label="Permalink to &quot;各字段翻译输入框&quot;">​</a></h4><p>作用：</p><ul><li>覆盖系统默认文案</li><li>只填写需要修改的字段，未填写内容会自动回退到默认文案</li></ul><p>适用场景：</p><ul><li>多语言店铺</li><li>需要自定义按钮、提示语、前台文案</li></ul><h2 id="_5-quote-limits" tabindex="-1">5. Quote Limits <a class="header-anchor" href="#_5-quote-limits" aria-label="Permalink to &quot;5. Quote Limits&quot;">​</a></h2><p>这部分用于控制报价数量限制、最小报价金额，以及变体级数量限制的批量导入。</p><p>这部分的详细说明已经整理到单独文档中，请直接查看：</p><ul><li><a href="./pricing-rules.html">定价与规则策略</a></li></ul><p>在该文档中可以看到：</p><ul><li>阶梯定价的配置方式</li><li><code>By product</code> 与 <code>By product variants</code> 的区别</li><li><code>Minimum quantity</code> / <code>Maximum quantity</code> 的含义</li><li><code>Minimum subtotal</code> 的限制逻辑</li><li>CSV 批量导入变体数量限制的字段与使用方式</li></ul><h2 id="_6-quote-file" tabindex="-1">6. Quote File <a class="header-anchor" href="#_6-quote-file" aria-label="Permalink to &quot;6. Quote File&quot;">​</a></h2><p>这部分主要控制导出、打印和附件上传。</p><h3 id="_6-1-print-export" tabindex="-1">6.1 Print &amp; Export <a class="header-anchor" href="#_6-1-print-export" aria-label="Permalink to &quot;6.1 Print &amp; Export&quot;">​</a></h3><h4 id="print-pdf" tabindex="-1">Print PDF <a class="header-anchor" href="#print-pdf" aria-label="Permalink to &quot;Print PDF&quot;">​</a></h4><p>作用：</p><ul><li>允许生成并下载报价单 PDF</li></ul><h4 id="export-excel" tabindex="-1">Export Excel <a class="header-anchor" href="#export-excel" aria-label="Permalink to &quot;Export Excel&quot;">​</a></h4><p>作用：</p><ul><li>允许导出报价列表为 Excel</li></ul><h3 id="_6-2-upload" tabindex="-1">6.2 Upload <a class="header-anchor" href="#_6-2-upload" aria-label="Permalink to &quot;6.2 Upload&quot;">​</a></h3><h4 id="enable-quote-attachments" tabindex="-1">Enable Quote Attachments <a class="header-anchor" href="#enable-quote-attachments" aria-label="Permalink to &quot;Enable Quote Attachments&quot;">​</a></h4><p>作用：</p><ul><li>允许商家或客户在报价消息中上传附件</li></ul><p>适用场景：</p><ul><li>客户上传图纸、需求文件、参考图片</li><li>商家回传报价附件或补充资料</li></ul><h4 id="customer-upload-limits" tabindex="-1">Customer upload limits <a class="header-anchor" href="#customer-upload-limits" aria-label="Permalink to &quot;Customer upload limits&quot;">​</a></h4><p>作用：</p><ul><li>控制客户前台上传附件的大小、数量和类型</li></ul><p>常见内容包括：</p><ul><li>单个文件大小限制</li><li>单次上传文件数量限制</li><li>允许上传的文件类型</li></ul><h2 id="_7-smartflow" tabindex="-1">7. SmartFlow <a class="header-anchor" href="#_7-smartflow" aria-label="Permalink to &quot;7. SmartFlow&quot;">​</a></h2><p>这部分主要控制沟通流程、状态流和自动审批相关能力。</p><h3 id="_7-1-communication-settings" tabindex="-1">7.1 Communication Settings <a class="header-anchor" href="#_7-1-communication-settings" aria-label="Permalink to &quot;7.1 Communication Settings&quot;">​</a></h3><p><img src="'+d+'" alt="communication"></p><h4 id="customer-reply-enabled" tabindex="-1">Customer reply enabled <a class="header-anchor" href="#customer-reply-enabled" aria-label="Permalink to &quot;Customer reply enabled&quot;">​</a></h4><p>作用：</p><ul><li>允许客户在前台给商家发送消息</li></ul><p>适用场景：</p><ul><li>商家和客户需要围绕报价反复沟通</li></ul><p><img src="'+c+'" alt="customer_reply"></p><h4 id="pro-workflow-progress-bar" tabindex="-1">Pro workflow progress bar <a class="header-anchor" href="#pro-workflow-progress-bar" aria-label="Permalink to &quot;Pro workflow progress bar&quot;">​</a></h4><p>作用：</p><ul><li>在报价流程中显示更完整的状态进度</li></ul><p><img src="'+h+'" alt="flow"></p><h4 id="customer-accept" tabindex="-1">Customer accept <a class="header-anchor" href="#customer-accept" aria-label="Permalink to &quot;Customer accept&quot;">​</a></h4><p>作用：</p><ul><li>允许客户在前台正式接受报价</li></ul><p><img src="'+m+'" alt="flow"></p><h4 id="activity-log" tabindex="-1">Activity log <a class="header-anchor" href="#activity-log" aria-label="Permalink to &quot;Activity log&quot;">​</a></h4><p>作用：</p><ul><li>显示报价流程中的系统活动记录</li></ul><p><img src="'+b+'" alt="log"></p><h3 id="_7-2-auto-approval" tabindex="-1">7.2 Auto Approval <a class="header-anchor" href="#_7-2-auto-approval" aria-label="Permalink to &quot;7.2 Auto Approval&quot;">​</a></h3><p>这部分用于自动审批报价。</p><p><img src="'+g+'" alt="auto-approval"></p><h4 id="enable-auto-approval" tabindex="-1">Enable auto approval <a class="header-anchor" href="#enable-auto-approval" aria-label="Permalink to &quot;Enable auto approval&quot;">​</a></h4><p>作用：</p><ul><li>启用后，符合条件的报价可以自动审批</li></ul><h4 id="minimum-amount-maximum-amount" tabindex="-1">Minimum amount / Maximum amount <a class="header-anchor" href="#minimum-amount-maximum-amount" aria-label="Permalink to &quot;Minimum amount / Maximum amount&quot;">​</a></h4><p>作用：</p><ul><li>设置自动审批的金额区间</li></ul><h4 id="max-discount-percent" tabindex="-1">Max discount percent <a class="header-anchor" href="#max-discount-percent" aria-label="Permalink to &quot;Max discount percent&quot;">​</a></h4><p>作用：</p><ul><li>设置允许自动审批的最大折扣比例（目录价格的总折扣不超过此百分比时自动审批）</li></ul><h2 id="_8-smtp" tabindex="-1">8. SMTP <a class="header-anchor" href="#_8-smtp" aria-label="Permalink to &quot;8. SMTP&quot;">​</a></h2><p>这部分用于配置邮件发件服务器，以及让报价通知邮件能够真正发送给客户。</p><p>SMTP 的详细说明已经整理到单独文档中，请直接查看：</p><ul><li><a href="./emails-notifications.html">邮件与通知</a></li></ul><p>在该文档中可以看到：</p><ul><li>SMTP 每个配置项的作用</li><li>常见主机、端口和加密方式的说明</li><li>如何测试 SMTP 连接</li><li>如何发送测试邮件验证实际送达</li></ul><h2 id="_9-email-integrations" tabindex="-1">9. Email integrations <a class="header-anchor" href="#_9-email-integrations" aria-label="Permalink to &quot;9. Email integrations&quot;">​</a></h2><p>这部分用于接入第三方邮件营销平台，例如 Klaviyo 和 Mailchimp。</p><p>Email integrations 的详细说明已经整理到单独文档中，请直接查看：</p><ul><li><a href="./emails-notifications.html">邮件与通知</a></li></ul><p>在该文档中可以看到：</p><ul><li>Klaviyo 与 Mailchimp 的用途说明</li><li>每个配置项的含义</li><li>每个字段的获取方式</li><li>如何验证连接是否成功</li><li>它们与 SMTP 的关系和区别</li></ul><h2 id="_10-使用建议" tabindex="-1">10. 使用建议 <a class="header-anchor" href="#_10-使用建议" aria-label="Permalink to &quot;10. 使用建议&quot;">​</a></h2><p>如果您刚开始配置 Settings，建议按这个顺序进行：</p><ol><li>先完成 <strong>General</strong> 的前台显示设置</li><li>再设置 <strong>Quote validity period</strong></li><li>如需限制报价规则，再配置 <strong>Quote Limits</strong></li><li>如需邮件通知，再配置 <strong>SMTP</strong> 和 <strong>Notifications</strong></li><li>如需更复杂自动化，再启用 <strong>SmartFlow</strong></li><li>如需营销平台同步，再设置 <strong>Email integrations</strong></li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>某些设置需要对应订阅计划才可用</li><li>某些前台显示项除了后台开启外，还需要 Theme App Embed 配合生效</li><li>SMTP 配置正确后，还需要在 Notifications 中启用对应通知事件，邮件才会真正发送</li><li>第三方集成不会自动替代 SMTP 通知，它们主要用于同步数据和营销自动化</li></ul>',215)])])}const A=e(q,[["render",f]]);export{Q as __pageData,A as default};
